use std::net::Ipv4Addr;

struct Packet {
    kind: PacketKind,
    data: String,
    sequence_number: u64,
}

enum PacketKind {
    Ack,
    Data,
    KeepAlive,
}

impl Packet {
    fn new(kind: PacketKind, data: &str, seq: u64) -> Self {
        Packet { kind, data: data.to_string(), sequence_number: seq }
    }
}

fn process_packet(packet: Packet) {
    match packet.kind {
        PacketKind::Ack => {
            println!("Processing ACK with sequence number: {}", packet.sequence_number);
        }
        PacketKind::Data => {
            let checksum = packet.data.len() as u32;
            println!("Processing DATA packet. Calculated checksum: {}", checksum);
        }
        PacketKind::KeepAlive => {
            println!("Ignoring KEEP_ALIVE signal.");
        }
    }
}

fn main() {
    let ack_packet = Packet::new(PacketKind::Ack, "", 100);
    let data_packet = Packet::new(PacketKind::Data, "SamplePayload", 101);
    let keepalive_packet = Packet::new(PacketKind::KeepAlive, "", 5);

    process_packet(ack_packet);
    process_packet(data_packet);
    process_packet(keepalive_packet);
}

use std::fmt::{self, Display};
use std::io;

enum OperationResult {
    Ok(String),
    IoError(io::Error),
    ParseError(String),
}

impl Display for OperationResult {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            OperationResult::Ok(s) => write!(f, "Success: {}", s),
            OperationResult::IoError(e) => write!(f, "Failed due to file issue: {}", e),
            OperationResult::ParseError(s) => write!(f, "Failed parsing input: {}", s),
        }
    }
}

impl From<io::Error> for OperationResult {
    fn from(err: io::Error) -> Self {
        OperationResult::IoError(err)
    }
}

struct DeviceState {
    connection_status: OperationResult,
    last_read_value: Option<String>,
}

impl DeviceState {
    fn process_event(input_type: &str, data: Result<String, io::Error>) -> Self {
        let result = match input_type {
            "OK_SIGNAL" => {
                match data {
                    Ok(s) => OperationResult::Ok(s),
                    Err(e) => OperationResult::from(e),
                }
            },
            "PARSE_DATA" => {
                if let Ok(s) = data.map(|s| s.to_lowercase()) {
                    OperationResult::ParseError(format!("Invalid format for: {}", s))
                } else {
                    OperationResult::ParseError("Could not determine input type".to_string())
                }
            },
            "IO_FAIL" => OperationResult::from(io::Error::new(io::ErrorKind::Other, "Simulated hardware disconnection")),
            _ => OperationResult::ParseError("Unknown event type received".to_string()),
        };

        DeviceState {
            connection_status: result,
            last_read_value: Some(format!("Processed {}", input_type)),
        }
    }
}

fn main() {
    let state1 = DeviceState::process_event("OK_SIGNAL", Ok("Auth Token 123".to_string()));
    println!("{}", state1.connection_status);

    let state2 = DeviceState::process_event("IO_FAIL", Err(io::Error::new(io::ErrorKind::BrokenPipe, "Pipe broken")));
    println!("{}", state2.connection_status);

    let state3 = DeviceState::process_event("UNKNOWN", Ok("Garbage".to_string()));
    println!("{}", state3.connection_status);
}

use std::collections::HashMap;

#[derive(Debug, Clone)]
enum ConnectionState {
    Initial,
    Connecting(u32),
    Authenticated(String),
    Failed(String),
}

struct GatewayHandler {
    states: HashMap<String, ConnectionState>,
}

impl GatewayHandler {
    fn new() -> Self {
        let mut states = HashMap::new();
        states.insert("user_A".to_string(), ConnectionState::Initial);
        GatewayHandler {
            states,
        }
    }

    fn update_state(&mut self, user_id: &str, new_state: ConnectionState) -> Result<(), String> {
        if !self.states.contains_key(user_id) {
            return Err(format!("User {} not found", user_id));
        }

        let current_state = self.states.get(user_id).unwrap().clone();

        match (current_state, &new_state) {
            (ConnectionState::Initial, ConnectionState::Connecting(port)) => {
                self.states.insert(user_id.to_string(), ConnectionState::Connecting(*port));
                Ok(())
            },
            (ConnectionState::Connecting(current_port), ConnectionState::Authenticated(token)) => {
                if current_port == 443 {
                    self.states.insert(user_id.to_string(), ConnectionState::Authenticated(token.clone()));
                    Ok(())
                } else {
                    Err("Must connect on port 443 first".to_string())
                }
            },
            (ConnectionState::Authenticated(_), ConnectionState::Failed(reason)) => {
                self.states.insert(user_id.to_string(), ConnectionState::Failed(reason.clone()));
                Ok(()) 
            },
            (_, _) => Err("Invalid state transition attempted".to_string()),
        }
    }

    fn get_status(&self, user_id: &str) -> String {
        match self.states.get(user_id).unwrap() {
            ConnectionState::Initial => "System Initializing".to_string(),
            ConnectionState::Connecting(port) => format!("Status: Connecting on port {}", port),
            ConnectionState::Authenticated(token) => format!("Status: Connected with token starting {}", &token[..std::cmp::min(4, token.len())]),
            ConnectionState::Failed(reason) => format!("Status: Failed due to '{}'.", reason),
        }
    }
}

fn main() {
    let mut handler = GatewayHandler::new();
    println!("{}", handler.get_status(&"user_A".to_string()));

    handler.update_state(&"user_A".to_string(), ConnectionState::Connecting(80)).unwrap();
    println!("{}", handler.get_status(&"user_A".to_string()));

    handler.update_state(&"user_A".to_string(), ConnectionState::Authenticated("jwt:abc123xyz".to_string())).unwrap();
    println!("{}", handler.get_status(&"user_A".to_string()));

    handler.update_state(&"user_A".to_string(), ConnectionState::Failed("Expired credentials".to_string())).unwrap();
    println!("{}", handler.get_status(&"user_A".to_string()));
}

use std::fmt::{self, Display};

#[derive(Debug)]
enum ButtonState {
    Released,
    Pressed(u8),
    Unknown(u8),
}

impl Display for ButtonState {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            ButtonState::Released => write!(f, "Not pressed"),
            ButtonState::Pressed(id) => write!(f, "Active button {}", id),
            ButtonState::Unknown(data) => write!(f, "Unexpected data {}", data),
        }
    }
}

struct DeviceHandler {
    state: ButtonState,
}

impl DeviceHandler {
    fn new() -> Self {
        DeviceHandler {
            state: ButtonState::Released,
        }
    }

    fn handle_input(&mut self, raw_data: u8) {
        let new_state = if raw_data == 0x01 {
            ButtonState::Pressed(raw_data)
        } else if raw_data == 0x00 {
            ButtonState::Released
        } else {
            ButtonState::Unknown(raw_data)
        };

        match new_state {
            ButtonState::Released => println!("Device: Input cleared."),
            ButtonState::Pressed(_) => println!("Device: Button activated."),
            ButtonState::Unknown(data) => println!("Device: Received unexpected data byte {}", data),
        }

        self.state = new_state;
    }
}

fn main() {
    let mut handler = DeviceHandler::new();
    handler.handle_input(0x01);
    handler.handle_input(0xFF);
    handler.handle_input(0x00);
}

use std::collections::HashMap;

#[derive(Debug)]
pub enum FirmwareState {
    InitialScan,
    ChecksumMismatch(String),
    SignatureInvalid,
    PatchApplied(u32),
}

fn process_state(state: FirmwareState) -> Result<HashMap<String, String>, &'static str> {
    match state {
        FirmwareState::InitialScan => Ok(HashMap::from([("Status".to_string(), "Scanning OK".to_string())])),
        FirmwareState::ChecksumMismatch(reason) => {
            println!("Warning: Checksum failed due to {}. Treating as critical.", reason);
            Err("Critical checksum failure detected.")
        },
        FirmwareState::SignatureInvalid => {
            println!("Error: Digital signature is missing or malformed.");
            Ok(HashMap::from([("Status".to_string(), "Failed Signature Check".to_string())]))
        },
        FirmwareState::PatchApplied(version) => {
            println!("Success: Firmware updated to version {}", version);
            Ok(HashMap::from([("Status".to_string(), format!("Updated to v{}", version).to_string()), ("Version".to_string(), "N/A".to_string())]))
        }
    }
}

pub fn main() {
    let state1 = FirmwareState::InitialScan;
    match process_state(state1) {
        Ok(data) => println!("Processed 1: {:?}", data),
        Err(e) => eprintln!("Error processing 1: {}", e),
    }

    let state2 = FirmwareState::ChecksumMismatch("Bad magic bytes found".to_string());
    match process_state(state2) {
        Ok(data) => println!("Processed 2: {:?}", data),
        Err(e) => eprintln!("Error processing 2: {}", e),
    }

    let state3 = FirmwareState::PatchApplied(0xDEADBEEF);
    match process_state(state3) {
        Ok(data) => println!("Processed 3: {:?}", data),
        Err(e) => eprintln!("Error processing 3: {}", e),
    }
}
